def underwriting_reply_filter(messages, sender, config):
    context = ' '.join([msg['content'] for msg in messages[-3:]])

    # Vex check for insurance discrimination
    result = vex.check({
        'policy_id': 'insurance-discrimination',
        'content': sender.last_message()['content'],
        'metadata': {
            'agent_role': sender.name,
            'protected_classes': ['race', 'gender', 'age', 'zip_correlation'],
            'decision_type': 'underwriting'
        }
    })

    if not result['pass']:
        return False, f"Compliance violation: {result['reason']}. Suggested: {result['remediation']}"

    return True, None

