class InsuranceLoopGuard:
    def __init__(self):
        self.turn_count = 0
        self.max_turns = 15
        self.token_spent = 0

    def check_loop(self, reply):
        self.turn_count += 1
        self.token_spent += len(reply)

        if self.turn_count > self.max_turns:
            vex.log_event({
                'event': 'loop_detected',
                'agent_conversation': True,
                'tokens': self.token_spent
            })
            return False, "Infinite loop detected - requires human review"

        if self.token_spent > 50000:
            return False, "Token limit exceeded for insurance decision"

        return True, None

loop_guard = InsuranceLoopGuard()

def autogen_loop_filter(reply):
    return loop_guard.check_loop(reply)

